export const areaCodeList = Object.keys(areaCodes).sort((a, b) => a.localeCompare(b))
export const areaCodeCount = areaCodeList.length

/** State/Province grouping for hub page */
export function getAreaCodesByState(): Record<string, AreaCodeData[]> {
  const byState: Record<string, AreaCodeData[]> = {}
  for (const data of Object.values(areaCodes)) {
    const key = `${data.state}, ${data.stateCode}`
    if (!byState[key]) byState[key] = []
    byState[key].push(data)
  }
  return byState
}

/** Timezone grouping */
export function getAreaCodesByTimezone(): Record<string, AreaCodeData[]> {
  const byTz: Record<string, AreaCodeData[]> = {}
  for (const data of Object.values(areaCodes)) {
    const key = data.tzAbbr
    if (!byTz[key]) byTz[key] = []
    byTz[key].push(data)
  }
  return byTz
}
